# Keep models/car.py unchanged for this step: Create two car objects.
class Car:
    def __init__(self, make, model, miles):
        self.make = make
        self.model = model
        self.miles = miles

    def drive(self, miles):
        self.miles += miles
        return self.miles

    def summary(self):
        return f"{self.make} {self.model} - {self.miles} miles"

